/**
 * Seed script: creates an admin user, two solvable problems (with hidden test
 * bundles uploaded to object storage), and a live contest wiring them together.
 *
 * Run with infra up and env loaded:
 *   pnpm --filter @arena/api exec tsx prisma/seed.ts
 */
import { PrismaClient } from "@prisma/client";
import { S3Client, PutObjectCommand, CreateBucketCommand } from "@aws-sdk/client-s3";
import { mkdtemp, writeFile, rm, readFile } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import * as tar from "tar";
import argon2 from "argon2";

const prisma = new PrismaClient();

const s3 = new S3Client({
  region: process.env.S3_REGION ?? "us-east-1",
  endpoint: process.env.S3_ENDPOINT,
  forcePathStyle: (process.env.S3_FORCE_PATH_STYLE ?? "true") === "true",
  credentials: {
    accessKeyId: process.env.S3_ACCESS_KEY ?? "minioadmin",
    secretAccessKey: process.env.S3_SECRET_KEY ?? "minioadmin",
  },
});
const BUCKET = process.env.S3_BUCKET ?? "arena-testcases";

async function packAndUpload(key: string, tests: { input: string; output: string }[]): Promise<void> {
  const dir = await mkdtemp(join(tmpdir(), "seed-tests-"));
  const tarPath = join(tmpdir(), `seed-${Date.now()}.tar`);
  try {
    const files: string[] = [];
    for (let i = 0; i < tests.length; i++) {
      const n = String(i + 1).padStart(2, "0");
      await writeFile(join(dir, `${n}.in`), tests[i].input);
      await writeFile(join(dir, `${n}.out`), tests[i].output);
      files.push(`${n}.in`, `${n}.out`);
    }
    await tar.create({ file: tarPath, cwd: dir }, files);
    const body = await readFile(tarPath);
    await s3.send(new PutObjectCommand({ Bucket: BUCKET, Key: key, Body: body, ContentType: "application/x-tar" }));
  } finally {
    await rm(dir, { recursive: true, force: true }).catch(() => {});
    await rm(tarPath).catch(() => {});
  }
}

interface ProblemSeed {
  slug: string;
  title: string;
  statement: string;
  editorial?: string;
  difficulty: "easy" | "med" | "hard";
  ratingValue: number;
  tags: string[];
  samples: { input: string; output: string }[];
  tests: { input: string; output: string }[];
}

// Editorials for the marquee interview-question problems — solution
// walkthroughs that add indexable, long-tail SEO depth to those pages. Keyed by
// slug and merged into the bank at seed time (also updated on re-seed).
const EDITORIALS: Record<string, string> = {
  "two-sum":
    "<h3>Approach</h3><p>The brute-force solution checks every pair of numbers in <code>O(n²)</code> time. We can do better with a hash map. As we scan the array once, for each value <code>x</code> we ask: have we already seen its complement <code>target − x</code>? If so, we've found the pair; if not, we record <code>x</code> and its index and move on.</p><h3>Why it works</h3><p>By storing each number's index as we go, the complement lookup is <code>O(1)</code>, so a single pass answers the question. Because we check for the complement <em>before</em> inserting the current element, we never pair an element with itself.</p><pre><code>seen = {}\nfor i, x in enumerate(nums):\n    if target - x in seen:\n        return [seen[target - x], i]\n    seen[x] = i</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n) — one pass. <strong>Space:</strong> O(n) for the hash map.</p>",
  "valid-parentheses":
    "<h3>Approach</h3><p>Bracket matching is the canonical use case for a <strong>stack</strong>. Scan left to right: push every opening bracket. On a closing bracket, the most recently opened bracket must be its match — so pop the stack and compare. If it doesn't match (or the stack is empty), the string is invalid.</p><h3>Key insight</h3><p>Valid nesting is <em>last-opened, first-closed</em> — exactly LIFO order, which is what a stack models. At the end, a valid string leaves the stack empty; anything left over means an unclosed bracket.</p><pre><code>pairs = {')':'(', ']':'[', '}':'{'}\nstack = []\nfor c in s:\n    if c in '([{': stack.append(c)\n    elif not stack or stack.pop() != pairs[c]:\n        return False\nreturn not stack</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(n) in the worst case (all opening brackets).</p>",
  "best-time-to-buy-and-sell-stock":
    "<h3>Approach</h3><p>You want the largest <code>price[j] − price[i]</code> with <code>j &gt; i</code>. A single pass suffices: track the <strong>minimum price seen so far</strong>, and at each day compute the profit if you sold today (today's price minus that running minimum), keeping the best.</p><h3>Why one pass works</h3><p>The best sell day only depends on the cheapest buy day <em>before</em> it. By carrying the running minimum forward, every day already knows the optimal buy price to its left, so no nested loop is needed.</p><pre><code>min_price = infinity\nbest = 0\nfor p in prices:\n    min_price = min(min_price, p)\n    best = max(best, p - min_price)\nreturn best</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "contains-duplicate":
    "<h3>Approach</h3><p>Add each number to a hash set as you go. If a number is already in the set, you've found a duplicate. If you finish the array without a collision, every value was unique.</p><h3>Alternative</h3><p>Sorting first makes duplicates adjacent, so a single scan comparing neighbours also works — that's O(n log n) time but O(1) extra space if you may modify the input. The hash-set method trades space for speed.</p><pre><code>seen = set()\nfor x in nums:\n    if x in seen: return True\n    seen.add(x)\nreturn False</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(n).</p>",
  "valid-palindrome":
    "<h3>Approach</h3><p>Use two pointers, one at each end. Skip any non-alphanumeric characters, compare the two characters case-insensitively, then move both inward. If any pair differs, it's not a palindrome; if the pointers cross, it is.</p><h3>Why two pointers</h3><p>A palindrome reads the same forwards and backwards, so the k-th character from the front must equal the k-th from the back. Comparing from both ends toward the middle checks exactly those constraints in a single O(n) pass with no extra string allocations.</p><pre><code>i, j = 0, len(s) - 1\nwhile i &lt; j:\n    while i &lt; j and not s[i].isalnum(): i += 1\n    while i &lt; j and not s[j].isalnum(): j -= 1\n    if s[i].lower() != s[j].lower(): return False\n    i, j = i + 1, j - 1\nreturn True</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "climbing-stairs":
    "<h3>Approach</h3><p>To reach step <code>n</code> your last move was either a single step (from <code>n−1</code>) or a double step (from <code>n−2</code>). So the number of ways satisfies <code>ways(n) = ways(n−1) + ways(n−2)</code> — the Fibonacci recurrence.</p><h3>From recursion to O(1) space</h3><p>Naïve recursion recomputes the same subproblems exponentially. Since each value only needs the previous two, we can iterate upward keeping just two running totals instead of a full table.</p><pre><code>a, b = 1, 1  # ways(0), ways(1)\nfor _ in range(n):\n    a, b = b, a + b\nreturn a</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "fizzbuzz":
    "<h3>Approach</h3><p>Loop from 1 to <code>n</code>. The only subtlety is order: a number divisible by both 3 and 5 (i.e. by 15) must print <code>FizzBuzz</code>. The cleanest way to guarantee that is to build the output by string concatenation — append <code>Fizz</code> when divisible by 3 and <code>Buzz</code> when divisible by 5 — which handles the combined case for free.</p><pre><code>for i in range(1, n+1):\n    out = ''\n    if i % 3 == 0: out += 'Fizz'\n    if i % 5 == 0: out += 'Buzz'\n    print(out or i)</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "reverse-string":
    "<h3>Approach</h3><p>Swap characters from the two ends toward the middle with two pointers, or use your language's built-in reverse. The two-pointer version reverses in place with no extra allocation.</p><pre><code>i, j = 0, len(s) - 1\nwhile i &lt; j:\n    s[i], s[j] = s[j], s[i]\n    i, j = i + 1, j - 1</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1) in place.</p>",
  "merge-sorted-arrays":
    "<h3>Approach</h3><p>Both inputs are already sorted, so walk them with two pointers, always taking the smaller current element — this is the merge step of merge sort. When one list runs out, append the remainder of the other.</p><pre><code>i = j = 0; out = []\nwhile i &lt; len(a) and j &lt; len(b):\n    if a[i] &lt;= b[j]: out.append(a[i]); i += 1\n    else: out.append(b[j]); j += 1\nout += a[i:] + b[j:]</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n + m). <strong>Space:</strong> O(n + m) for the output.</p>",
  "max-subarray":
    "<h3>Approach (Kadane's algorithm)</h3><p>Scan left to right keeping the best subarray sum <em>ending at the current position</em>. At each element you either extend the previous run or start fresh at the current element — whichever is larger. Track the maximum of those as you go.</p><h3>Insight</h3><p>If the running sum ever goes negative it can only hurt what follows, so you drop it and restart. That greedy reset is what makes a single pass sufficient.</p><pre><code>best = cur = nums[0]\nfor x in nums[1:]:\n    cur = max(x, cur + x)\n    best = max(best, cur)\nreturn best</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "roman-to-integer":
    "<h3>Approach</h3><p>Map each symbol to its value and scan left to right. Normally you add, but in subtractive pairs (like <code>IV</code> = 4 or <code>IX</code> = 9) a smaller value sits before a larger one — so if the current symbol's value is less than the next symbol's, subtract it instead of adding.</p><pre><code>val = {'I':1,'V':5,'X':10,'L':50,'C':100,'D':500,'M':1000}\ntotal = 0\nfor i, c in enumerate(s):\n    if i+1 &lt; len(s) and val[c] &lt; val[s[i+1]]:\n        total -= val[c]\n    else:\n        total += val[c]\nreturn total</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "single-number":
    "<h3>Approach (XOR trick)</h3><p>XOR has two useful properties: <code>x ^ x = 0</code> and <code>x ^ 0 = x</code>. XOR every element together — each value that appears twice cancels to 0, leaving only the element that appears once.</p><pre><code>ans = 0\nfor x in nums:\n    ans ^= x\nreturn ans</code></pre><h3>Why it beats a hash set</h3><p>A hash set also solves it in O(n) time but needs O(n) space; XOR does it in O(1) space with no bookkeeping.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "majority-element":
    "<h3>Approach (Boyer–Moore voting)</h3><p>Keep a candidate and a counter. For each element: if the counter is 0, adopt the element as the new candidate; then increment the counter if it matches the candidate, else decrement. The element appearing more than n/2 times survives.</p><h3>Why it works</h3><p>Pairing each majority element with a different element cancels both out. Since the majority occurs more than half the time it can't be fully cancelled, so whatever remains is the answer.</p><pre><code>count = 0; cand = None\nfor x in nums:\n    if count == 0: cand = x\n    count += 1 if x == cand else -1\nreturn cand</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "product-of-array-except-self":
    "<h3>Approach</h3><p>Division is disallowed (and breaks on zeros), so build the answer from two sweeps. First pass left-to-right: each position holds the product of everything to its left. Second pass right-to-left: multiply in the product of everything to its right.</p><pre><code>n = len(nums); res = [1]*n\nleft = 1\nfor i in range(n):\n    res[i] = left; left *= nums[i]\nright = 1\nfor i in range(n-1, -1, -1):\n    res[i] *= right; right *= nums[i]\nreturn res</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1) extra, besides the output.</p>",
  "move-zeroes":
    "<h3>Approach</h3><p>Keep a write pointer for the next non-zero slot. Scan the array; each time you hit a non-zero, place it at the write pointer and advance it. After the scan, fill the remaining slots with zeros. The relative order of non-zeros is preserved.</p><pre><code>w = 0\nfor x in nums:\n    if x != 0:\n        nums[w] = x; w += 1\nwhile w &lt; len(nums):\n    nums[w] = 0; w += 1</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1) in place.</p>",
  "missing-number":
    "<h3>Approach</h3><p>The values should form a full <code>0..n</code> range with exactly one gap. The sum of <code>0..n</code> is <code>n(n+1)/2</code>; subtract the actual array sum and what's left is the missing value.</p><pre><code>n = len(nums)\nreturn n*(n+1)//2 - sum(nums)</code></pre><h3>Alternative</h3><p>XOR-ing all indices <code>0..n</code> with all the values also cancels every present number and leaves the missing one — handy if the sum might overflow.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "house-robber":
    "<h3>Approach (dynamic programming)</h3><p>At each house you choose: skip it (keep the best total up to the previous house), or rob it (its value plus the best total up to two houses back, since adjacent houses can't both be robbed). Take the larger option.</p><pre><code>prev2 = prev1 = 0\nfor x in nums:\n    prev2, prev1 = prev1, max(prev1, prev2 + x)\nreturn prev1</code></pre><h3>Insight</h3><p>Only the last two running totals ever matter, so the full DP table collapses to two variables.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "coin-change":
    "<h3>Approach (dynamic programming)</h3><p>Let <code>dp[a]</code> be the fewest coins summing to <code>a</code>. Start with <code>dp[0] = 0</code> and everything else infinity. For each amount try every coin: <code>dp[a] = min(dp[a], dp[a - coin] + 1)</code>. The answer is <code>dp[amount]</code>, or -1 if it stayed infinite.</p><pre><code>dp = [0] + [inf]*amount\nfor a in range(1, amount+1):\n    for c in coins:\n        if c &lt;= a:\n            dp[a] = min(dp[a], dp[a-c] + 1)\nreturn dp[amount] if dp[amount] != inf else -1</code></pre><h3>Note</h3><p>Greedy (largest coin first) fails for arbitrary denominations, so DP is needed for the general case.</p><h3>Complexity</h3><p><strong>Time:</strong> O(amount × coins). <strong>Space:</strong> O(amount).</p>",
  "longest-common-subsequence":
    "<h3>Approach (2D dynamic programming)</h3><p>Let <code>dp[i][j]</code> be the LCS length of the first <code>i</code> characters of <code>a</code> and first <code>j</code> of <code>b</code>. If the current characters match, extend the diagonal: <code>dp[i-1][j-1] + 1</code>. Otherwise take the better of dropping one character from either string: <code>max(dp[i-1][j], dp[i][j-1])</code>.</p><pre><code>for i in range(1, len(a)+1):\n    for j in range(1, len(b)+1):\n        if a[i-1] == b[j-1]:\n            dp[i][j] = dp[i-1][j-1] + 1\n        else:\n            dp[i][j] = max(dp[i-1][j], dp[i][j-1])\nreturn dp[len(a)][len(b)]</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n × m). <strong>Space:</strong> O(n × m), reducible to O(min(n, m)).</p>",
  "kth-largest":
    "<h3>Approach</h3><p>The simplest correct answer sorts descending and takes index <code>k-1</code> — O(n log n). To do better, keep a min-heap of the <code>k</code> largest values seen so far: push each element, and pop when the heap grows beyond size <code>k</code>. The heap's smallest element is then the k-th largest overall.</p><pre><code>import heapq\nh = []\nfor x in nums:\n    heapq.heappush(h, x)\n    if len(h) &gt; k: heapq.heappop(h)\nreturn h[0]</code></pre><h3>Complexity</h3><p><strong>Heap:</strong> O(n log k) time, O(k) space. Quickselect averages O(n) time.</p>",
  "anagram-check":
    "<p><strong>Valid Anagram</strong> is a classic string interview question: two strings are anagrams when one is a rearrangement of the other — which happens exactly when they share the same characters with the same frequencies.</p><h3>Approach</h3><p>Tally the characters of the first string, then subtract using the second. If a length differs or any count drops below zero, they aren't anagrams. A 26-slot array (lowercase letters) or a hash map both work.</p><pre><code>if len(a) != len(b): return False\ncount = Counter(a)\nfor c in b:\n    count[c] -= 1\n    if count[c] &lt; 0: return False\nreturn True</code></pre><h3>Alternative</h3><p>Sorting both strings and comparing also works in O(n log n); frequency counting is the faster O(n) route.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1) for a fixed alphabet.</p>",
  "longest-increasing-subsequence":
    "<p>The <strong>Longest Increasing Subsequence</strong> (LIS) is a staple dynamic-programming interview problem: find the length of the longest strictly increasing subsequence, where elements need not be contiguous.</p><h3>O(n²) dynamic programming</h3><p>Let <code>dp[i]</code> be the LIS length ending at index <code>i</code>; for each <code>i</code>, take the best over every earlier <code>j</code> with <code>nums[j] &lt; nums[i]</code>.</p><h3>O(n log n) patience sorting</h3><p>Maintain <code>tails</code>, where <code>tails[k]</code> is the smallest possible tail of an increasing subsequence of length <code>k+1</code>. Binary-search each value's position; if it lands past the end, the LIS grew by one.</p><pre><code>tails = []\nfor x in nums:\n    i = bisect_left(tails, x)\n    if i == len(tails): tails.append(x)\n    else: tails[i] = x\nreturn len(tails)</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n log n). <strong>Space:</strong> O(n).</p>",
  "edit-distance":
    "<p><strong>Edit Distance</strong> (Levenshtein distance) is a well-known dynamic-programming interview problem: the fewest single-character insertions, deletions, or substitutions to turn one string into another.</p><h3>Approach</h3><p>Let <code>dp[i][j]</code> be the edit distance between the first <code>i</code> characters of <code>a</code> and first <code>j</code> of <code>b</code>. If the current characters match, no edit is needed. Otherwise it's 1 plus the cheapest of insert, delete, or substitute.</p><pre><code>if a[i-1] == b[j-1]:\n    dp[i][j] = dp[i-1][j-1]\nelse:\n    dp[i][j] = 1 + min(dp[i-1][j],    # delete\n                       dp[i][j-1],    # insert\n                       dp[i-1][j-1])  # substitute</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n × m). <strong>Space:</strong> O(n × m), reducible to O(min(n, m)) with a rolling row.</p>",
  "knapsack":
    "<p>The <strong>0/1 Knapsack</strong> is a foundational dynamic-programming interview problem: maximise the total value packed into a bag of fixed capacity, taking each item at most once.</p><h3>Approach</h3><p>Let <code>dp[w]</code> be the best value for capacity <code>w</code>. Process items one at a time, iterating capacity <strong>downward</strong>: <code>dp[w] = max(dp[w], dp[w - weight] + value)</code>.</p><pre><code>dp = [0]*(W+1)\nfor wt, val in items:\n    for w in range(W, wt-1, -1):\n        dp[w] = max(dp[w], dp[w-wt] + val)\nreturn dp[W]</code></pre><h3>Why iterate downward</h3><p>Going high-to-low guarantees <code>dp[w-wt]</code> still refers to a state <em>without</em> the current item — that's exactly what enforces the 0/1 (each item once) rule, versus the unbounded knapsack which iterates upward.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n × W). <strong>Space:</strong> O(W).</p>",
  "unique-paths":
    "<p><strong>Unique Paths</strong> is a classic grid dynamic-programming (and combinatorics) interview problem: a robot at the top-left of an m×n grid moving only right or down — how many distinct paths reach the bottom-right?</p><h3>DP approach</h3><p>Each cell is reachable only from the cell above or to its left, so <code>paths[i][j] = paths[i-1][j] + paths[i][j-1]</code>, with the first row and column all 1.</p><h3>Combinatorial shortcut</h3><p>Every path makes exactly <code>m-1</code> downs and <code>n-1</code> rights in some order, so the answer is the binomial coefficient <code>C(m+n-2, m-1)</code>.</p><pre><code>from math import comb\nreturn comb(m + n - 2, m - 1)</code></pre><h3>Complexity</h3><p><strong>DP:</strong> O(m × n) time. <strong>Combinatorial:</strong> O(min(m, n)) time, O(1) space.</p>",
  "longest-palindromic-substring":
    "<p><strong>Longest Palindromic Substring</strong> is a popular string interview problem: find the longest contiguous substring that reads the same forwards and backwards.</p><h3>Expand around center</h3><p>Every palindrome has a center — a single character (odd length) or the gap between two characters (even length). There are <code>2n-1</code> centers; expand outward from each while the characters match, keeping the longest span.</p><pre><code>def expand(l, r):\n    while l &gt;= 0 and r &lt; n and s[l] == s[r]:\n        l -= 1; r += 1\n    return r - l - 1  # length of the palindrome</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n²), fast in practice. Manacher's algorithm achieves O(n) but is rarely needed in interviews. <strong>Space:</strong> O(1).</p>",
  "max-product-subarray":
    "<p><strong>Maximum Product Subarray</strong> is a well-known array/DP interview problem and a subtle twist on Maximum Subarray: a negative value can flip the sign, so the smallest (most negative) running product matters too.</p><h3>Approach</h3><p>Track both the maximum and minimum product ending at the current index. On a negative number the previous min becomes the new max and vice versa, so swap them before updating.</p><pre><code>best = hi = lo = nums[0]\nfor x in nums[1:]:\n    if x &lt; 0: hi, lo = lo, hi\n    hi = max(x, hi * x)\n    lo = min(x, lo * x)\n    best = max(best, hi)\nreturn best</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "search-insert-position":
    "<p><strong>Search Insert Position</strong> is a fundamental <strong>binary search</strong> interview problem: in a sorted array return the index of a target, or the index where it would be inserted to keep the array sorted.</p><h3>Approach</h3><p>Binary-search for the target; when it's absent, the stopping point <code>lo</code> is exactly the insertion index — the number of elements strictly less than the target. This is the reusable <em>lower-bound</em> pattern.</p><pre><code>lo, hi = 0, len(nums)\nwhile lo &lt; hi:\n    mid = (lo + hi) // 2\n    if nums[mid] &lt; target: lo = mid + 1\n    else: hi = mid\nreturn lo</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(log n). <strong>Space:</strong> O(1).</p>",
  "plus-one":
    "<p><strong>Plus One</strong> is a common array/math interview problem: given the digits of a number (most significant first), add one and return the resulting digits — handling the carry that can ripple through trailing 9s.</p><h3>Approach</h3><p>Walk from the least significant digit. If a digit is below 9, increment it and you're done. If it's 9, set it to 0 and carry left. If every digit was 9 (999 → 1000), prepend a leading 1.</p><pre><code>for i in range(len(d)-1, -1, -1):\n    if d[i] &lt; 9:\n        d[i] += 1\n        return d\n    d[i] = 0\nreturn [1] + d</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1) (O(n) only in the all-nines case).</p>",
  "length-of-last-word":
    "<p><strong>Length of Last Word</strong> is a simple string-parsing interview question: return the length of the final word in a string that may have trailing spaces and multiple separators.</p><h3>Approach</h3><p>Scan from the end: skip any trailing spaces, then count characters until you hit the next space or the start of the string. Walking backwards avoids splitting the whole string.</p><pre><code>i = len(s) - 1\nwhile i &gt;= 0 and s[i] == ' ': i -= 1\nlength = 0\nwhile i &gt;= 0 and s[i] != ' ':\n    length += 1; i -= 1\nreturn length</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "nth-fibonacci":
    "<p><strong>Nth Fibonacci Number</strong> is a classic introduction to dynamic programming: each number is the sum of the previous two, with <code>F(0) = 0</code> and <code>F(1) = 1</code>.</p><h3>Approach</h3><p>Naïve recursion is O(2ⁿ) because it recomputes the same subproblems. Iterate bottom-up instead, carrying just the last two values — no array required.</p><pre><code>a, b = 0, 1\nfor _ in range(n):\n    a, b = b, a + b\nreturn a</code></pre><h3>Going further</h3><p>Fibonacci can be computed in O(log n) with matrix exponentiation or fast doubling — a nice interview follow-up.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "gcd-two":
    "<p><strong>Greatest Common Divisor</strong> is a fundamental number-theory interview problem, solved elegantly by the <strong>Euclidean algorithm</strong>.</p><h3>Approach</h3><p>The GCD of <code>a</code> and <code>b</code> equals the GCD of <code>b</code> and <code>a mod b</code>. Repeatedly replace the pair until the remainder hits 0; the surviving number is the answer.</p><pre><code>while b:\n    a, b = b, a % b\nreturn a</code></pre><h3>Why it works</h3><p>Any common divisor of <code>a</code> and <code>b</code> also divides <code>a mod b</code>, so the set of common divisors is preserved while the numbers shrink rapidly.</p><h3>Complexity</h3><p><strong>Time:</strong> O(log(min(a, b))). <strong>Space:</strong> O(1).</p>",
  "is-prime":
    "<p><strong>Primality Test</strong> is a classic number-theory interview question: determine whether an integer <code>n</code> is prime.</p><h3>Approach</h3><p>Numbers below 2 aren't prime. Otherwise test divisibility only up to <code>√n</code> — a factor larger than the square root would force a matching factor smaller than it, which you'd already have found. Skipping even candidates after 2 halves the work.</p><pre><code>if n &lt; 2: return False\nif n % 2 == 0: return n == 2\ni = 3\nwhile i*i &lt;= n:\n    if n % i == 0: return False\n    i += 2\nreturn True</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(√n). <strong>Space:</strong> O(1).</p>",
  "count-primes":
    "<p><strong>Count Primes</strong> is a classic number-theory interview problem best solved with the <strong>Sieve of Eratosthenes</strong>: count how many primes are ≤ n.</p><h3>Approach</h3><p>Mark everything prime, then for each prime <code>p</code> from 2 upward, cross out its multiples starting at <code>p²</code>. Starting at <code>p²</code> rather than <code>2p</code> avoids redundant work, since smaller multiples were already crossed out by smaller primes.</p><pre><code>sieve = [True]*(n+1)\nsieve[0] = sieve[1] = False\nfor p in range(2, int(n**0.5)+1):\n    if sieve[p]:\n        for m in range(p*p, n+1, p):\n            sieve[m] = False\nreturn sum(sieve)</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n log log n). <strong>Space:</strong> O(n).</p>",
  "reverse-integer":
    "<p><strong>Reverse Integer</strong> is a common math interview question: reverse the digits of a signed integer, preserving the sign and dropping leading zeros (120 → 21).</p><h3>Approach</h3><p>Peel digits off the end with <code>n % 10</code> and rebuild with <code>res = res*10 + digit</code>, remembering the sign. Because the result is built numerically, trailing zeros vanish on their own.</p><pre><code>sign = -1 if n &lt; 0 else 1\nn = abs(n); res = 0\nwhile n:\n    res = res*10 + n % 10\n    n //= 10\nreturn sign * res</code></pre><h3>Watch out</h3><p>In fixed-width languages, guard against 32-bit overflow of the reversed value.</p><h3>Complexity</h3><p><strong>Time:</strong> O(d) in the number of digits. <strong>Space:</strong> O(1).</p>",
  "subset-sum":
    "<p><strong>Subset Sum</strong> is a canonical dynamic-programming interview problem: decide whether some subset of the numbers adds up to exactly a target.</p><h3>Approach</h3><p>Use a boolean DP where <code>dp[t]</code> is true when some subset sums to <code>t</code>. Start with <code>dp[0] = true</code>. For each number, iterate the target <strong>downward</strong> and set <code>dp[t] = dp[t] or dp[t - num]</code> — downward so each number is used at most once.</p><pre><code>dp = [True] + [False]*target\nfor num in nums:\n    for t in range(target, num-1, -1):\n        if dp[t-num]: dp[t] = True\nreturn dp[target]</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n × target). <strong>Space:</strong> O(target). Subset Sum is NP-complete in general; this pseudo-polynomial DP is efficient when the target is bounded.</p>",
  "balanced-brackets":
    "<p><strong>Balanced Brackets</strong> is a classic stack interview problem: verify that every opening bracket is closed by the correct type in the right order across <code>()</code>, <code>[]</code>, and <code>{}</code>.</p><h3>Approach</h3><p>Push each opening bracket onto a stack. On a closing bracket the top of the stack must be its matching opener — pop and compare; if it doesn't match, or the stack is empty, the string is unbalanced. A valid string ends with an empty stack.</p><pre><code>pairs = {')':'(', ']':'[', '}':'{'}\nstack = []\nfor c in s:\n    if c in '([{': stack.append(c)\n    elif not stack or stack.pop() != pairs[c]:\n        return False\nreturn not stack</code></pre><h3>Note</h3><p>With a single bracket type you could drop the stack and track a running counter, but multiple types need the stack to remember <em>which</em> bracket is open.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(n).</p>",
  "power-mod":
    "<p><strong>Modular Exponentiation</strong> computes <code>aᵇ mod m</code> efficiently — a core operation in cryptography (RSA, Diffie–Hellman) and a frequent interview question. Computing <code>aᵇ</code> directly overflows and is far too slow for large exponents.</p><h3>Fast (binary) exponentiation</h3><p>Square the base repeatedly and multiply it into the result whenever the current bit of the exponent is 1, reducing <code>mod m</code> at every step to keep the numbers small.</p><pre><code>result = 1\na %= m\nwhile b &gt; 0:\n    if b &amp; 1:\n        result = result * a % m\n    a = a * a % m\n    b &gt;&gt;= 1\nreturn result</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(log b). <strong>Space:</strong> O(1).</p>",
  "count-set-bits":
    "<p><strong>Count Set Bits</strong> — the Hamming weight or population count — asks how many 1s appear in a number's binary representation, a staple bit-manipulation interview question.</p><h3>Brian Kernighan's algorithm</h3><p>The expression <code>n &amp; (n - 1)</code> clears the lowest set bit. Repeat until <code>n</code> is 0, counting iterations, so you loop once per set bit instead of once per bit.</p><pre><code>count = 0\nwhile n:\n    n &amp;= n - 1\n    count += 1\nreturn count</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(set bits). <strong>Space:</strong> O(1). Most languages also expose a built-in popcount (<code>Integer.bitCount</code>, <code>__builtin_popcountll</code>).</p>",
  "sum-of-divisors":
    "<p><strong>Sum of Divisors</strong> asks for the sum of all positive divisors of <code>n</code> — a number-theory problem whose key idea is to avoid a full O(n) scan.</p><h3>Approach</h3><p>Divisors come in pairs: if <code>d</code> divides <code>n</code>, so does <code>n / d</code>. Iterate only up to <code>√n</code>, adding both members of each pair — but count a repeated divisor once when <code>d = n / d</code> for a perfect square.</p><pre><code>total = 0; d = 1\nwhile d*d &lt;= n:\n    if n % d == 0:\n        total += d\n        if d != n // d:\n            total += n // d\n    d += 1\nreturn total</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(√n). <strong>Space:</strong> O(1).</p>",
  "nth-prime":
    "<p><strong>Nth Prime</strong> asks for the n-th prime number (the 1st being 2), combining primality testing with counting.</p><h3>Approach</h3><p>Test candidates one by one — each by trial division up to its square root — until you've found <code>n</code> primes. For large <code>n</code>, sieving up to an estimated bound (around <code>n ln n</code>) is faster than testing individually.</p><pre><code>count = 0; num = 1\nwhile count &lt; n:\n    num += 1\n    if is_prime(num):\n        count += 1\nreturn num</code></pre><h3>Complexity</h3><p><strong>Trial division:</strong> roughly O(n √p) for the n-th prime <code>p</code>; a sieve is faster at scale.</p>",
  "second-largest":
    "<p><strong>Second Largest Element</strong> asks for the second-largest <em>distinct</em> value — most elegantly solved in a single pass rather than by sorting.</p><h3>Approach</h3><p>Track the largest and second-largest seen so far. For each value: if it beats the largest, the old largest slides into second place; otherwise, if it sits strictly between the two, it becomes the new second.</p><pre><code>first = second = -inf\nfor x in nums:\n    if x &gt; first:\n        second = first; first = x\n    elif first &gt; x &gt; second:\n        second = x\nreturn second</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1) — versus O(n log n) if you sort.</p>",
  "most-frequent":
    "<p><strong>Most Frequent Element</strong> asks for the value that appears most often, breaking ties by the smallest value — a direct application of hash-map frequency counting.</p><h3>Approach</h3><p>Count occurrences in one pass, then scan the counts for the maximum, preferring the smaller value on a tie.</p><pre><code>from collections import Counter\ncounts = Counter(nums)\nbest, best_count = None, -1\nfor v in sorted(counts):\n    if counts[v] &gt; best_count:\n        best, best_count = v, counts[v]\nreturn best</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(k) for k distinct values.</p>",
  "meeting-rooms":
    "<p><strong>Minimum Meeting Rooms</strong> is a classic interval-scheduling interview problem: given meeting start and end times, find the greatest number that overlap at once — that's how many rooms you need.</p><h3>Approach (chronological sweep)</h3><p>Sort start times and end times separately. Sweep through the starts; before each meeting begins, free every room whose meeting has already ended. The running count of busy rooms peaks at the answer.</p><pre><code>starts.sort(); ends.sort()\nrooms = peak = j = 0\nfor s in starts:\n    while ends[j] &lt;= s:\n        j += 1; rooms -= 1\n    rooms += 1\n    peak = max(peak, rooms)\nreturn peak</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n log n). <strong>Space:</strong> O(n).</p>",
  "meeting-overlap":
    "<p>This problem asks whether a person can attend every meeting with no overlap — a gentle introduction to interval scheduling.</p><h3>Approach</h3><p>Sort the meetings by start time. If any meeting begins before the previous one ends, there's a conflict; otherwise they all fit.</p><pre><code>intervals.sort()\nfor i in range(1, len(intervals)):\n    if intervals[i][0] &lt; intervals[i-1][1]:\n        return False  # overlap\nreturn True</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n log n) for the sort. <strong>Space:</strong> O(1) beyond it.</p>",
  "luhn-check":
    "<p><strong>Credit Card Validation</strong> uses the <strong>Luhn algorithm</strong>, a checksum that catches most single-digit typos and adjacent transpositions — the same check that guards real card numbers.</p><h3>Approach</h3><p>Starting from the rightmost digit, double every second digit; if a doubled value exceeds 9, subtract 9 (the same as summing its two digits). Sum everything — the number is valid when the total is divisible by 10.</p><pre><code>total = 0; double = False\nfor d in reversed(digits):\n    if double:\n        d *= 2\n        if d &gt; 9: d -= 9\n    total += d\n    double = not double\nreturn total % 10 == 0</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "caesar-cipher":
    "<p>The <strong>Caesar Cipher</strong> shifts each letter a fixed number of places through the alphabet — one of the oldest ciphers and a classic string / modular-arithmetic exercise.</p><h3>Approach</h3><p>Map each letter to 0–25, add the shift, wrap with <code>mod 26</code>, and map back — preserving case and leaving non-letters untouched.</p><pre><code>def shift(c, k):\n    if c.isupper():\n        return chr((ord(c) - 65 + k) % 26 + 65)\n    if c.islower():\n        return chr((ord(c) - 97 + k) % 26 + 97)\n    return c</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(n) for the output. A shift of 13 is the well-known ROT13.</p>",
  "run-length-encode":
    "<p><strong>Run-Length Encoding</strong> (RLE) is a simple lossless compression scheme and a common string task: replace each run of a repeated character with the character followed by the run length (<code>aaabb</code> → <code>a3b2</code>).</p><h3>Approach</h3><p>Scan the string, extending the current run while characters match; when it ends, emit the character and its count, then start the next run.</p><pre><code>out = []\ni = 0\nwhile i &lt; len(s):\n    j = i\n    while j &lt; len(s) and s[j] == s[i]: j += 1\n    out.append(s[i] + str(j - i))\n    i = j\nreturn ''.join(out)</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(n).</p>",
  "matrix-transpose":
    "<p><strong>Transpose a Matrix</strong> flips a grid over its main diagonal so rows become columns — a fundamental matrix-manipulation task.</p><h3>Approach</h3><p>The value at row <code>i</code>, column <code>j</code> moves to row <code>j</code>, column <code>i</code>. For a non-square grid, allocate a fresh <code>cols × rows</code> matrix and copy each element to its transposed position.</p><pre><code>T = [[0]*rows for _ in range(cols)]\nfor i in range(rows):\n    for j in range(cols):\n        T[j][i] = M[i][j]\nreturn T</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(rows × cols). <strong>Space:</strong> O(rows × cols); a square matrix transposes in place in O(1) extra space.</p>",
  "budget-shopping":
    "<p><strong>Shopping on a Budget</strong> asks for the maximum number of items you can buy without exceeding a budget — a textbook <strong>greedy</strong> problem.</p><h3>Approach</h3><p>To fit the most items, always buy the cheapest one available. Sort prices ascending and take them while the budget holds, stopping at the first you can't afford.</p><pre><code>prices.sort()\nspent = count = 0\nfor p in prices:\n    if spent + p &gt; budget: break\n    spent += p; count += 1\nreturn count</code></pre><h3>Why greedy is optimal</h3><p>Any optimal set of <code>k</code> items can be swapped cheapest-for-cheapest into the <code>k</code> lowest-priced items without raising the cost — so taking the cheapest first never loses.</p><h3>Complexity</h3><p><strong>Time:</strong> O(n log n). <strong>Space:</strong> O(1).</p>",
  "make-change":
    "<p><strong>Cash Register Change</strong> asks for the fewest coins to make an amount using U.S. denominations (25, 10, 5, 1) — a classic <strong>greedy</strong> problem.</p><h3>Approach</h3><p>Repeatedly take the largest coin that fits. For the U.S. (canonical) coin system this greedy choice is provably optimal.</p><pre><code>count = 0\nfor coin in [25, 10, 5, 1]:\n    count += amount // coin\n    amount %= coin\nreturn count</code></pre><h3>Important caveat</h3><p>Greedy only works for <em>canonical</em> coin systems. For arbitrary denominations it can fail (e.g. coins 1, 3, 4 making 6), where you need the dynamic-programming approach from Coin Change.</p><h3>Complexity</h3><p><strong>Time:</strong> O(coin types). <strong>Space:</strong> O(1).</p>",
  "dna-hamming":
    "<p><strong>DNA Mutations</strong> counts the positions at which two equal-length strands differ — the <strong>Hamming distance</strong>, used throughout genetics and error-correcting codes.</p><h3>Approach</h3><p>Walk both strings in lockstep and count mismatches. Because the lengths are equal, a single pass suffices.</p><pre><code>return sum(1 for x, y in zip(a, b) if x != y)</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n). <strong>Space:</strong> O(1).</p>",
  "ip-to-int":
    "<p><strong>IP Address to Integer</strong> converts dotted-quad IPv4 (like <code>192.168.1.1</code>) into its 32-bit integer value — a common systems/networking task.</p><h3>Approach</h3><p>Each of the four octets occupies 8 bits. Split on the dots and combine them positionally — <code>a·2²⁴ + b·2¹⁶ + c·2⁸ + d</code> — or shift-and-or each octet into place.</p><pre><code>a, b, c, d = map(int, ip.split('.'))\nreturn (a &lt;&lt; 24) | (b &lt;&lt; 16) | (c &lt;&lt; 8) | d</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(1) — always four octets. <strong>Space:</strong> O(1).</p>",
  "binary-to-decimal":
    "<p><strong>Binary to Decimal</strong> converts a base-2 string to its integer value — a fundamental number-base problem.</p><h3>Approach (Horner's method)</h3><p>Process the bits left to right, doing <code>value = value * 2 + bit</code> for each. This folds in every place value without ever computing powers of two explicitly.</p><pre><code>value = 0\nfor ch in s:\n    value = value * 2 + (ord(ch) - ord('0'))\nreturn value</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n) in the number of bits. <strong>Space:</strong> O(1).</p>",
  "decimal-to-binary":
    "<p><strong>Decimal to Binary</strong> converts a non-negative integer to its base-2 representation — the inverse of binary-to-decimal.</p><h3>Approach</h3><p>Repeatedly divide by 2, collecting the remainders; those are the binary digits produced least-significant first, so reverse them at the end. Treat 0 as a special case.</p><pre><code>if n == 0: return '0'\nbits = []\nwhile n:\n    bits.append(str(n % 2))\n    n //= 2\nreturn ''.join(reversed(bits))</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(log n). <strong>Space:</strong> O(log n).</p>",
  "gcd-array":
    "<p><strong>GCD of an Array</strong> extends the pairwise greatest common divisor to a whole list — a number-theory problem built on the Euclidean algorithm.</p><h3>Approach</h3><p>The GCD is associative: <code>gcd(a, b, c) = gcd(gcd(a, b), c)</code>. Fold the array carrying a running GCD — it only ever shrinks, and reaching 1 lets you stop early.</p><pre><code>from math import gcd\ng = 0\nfor x in nums:\n    g = gcd(g, x)\n    if g == 1: break\nreturn g</code></pre><h3>Complexity</h3><p><strong>Time:</strong> O(n log(max value)). <strong>Space:</strong> O(1).</p>",
};

